import React from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import { AuthProvider, useAuth } from './contexts/AuthContext';
import AuthPage from './pages/AuthPage';
import ClientDashboard from './pages/ClientDashboard';
import AgencyDashboard from './pages/AgencyDashboard';
import './styles/App.css';

// Composant pour protéger les routes
const ProtectedRoute = ({ children, requireClient, requireAgency }) => {
  const { isAuthenticated, isClient, isAgency, loading } = useAuth();

  if (loading) {
    return (
      <div className="loading-screen">
        <div className="spinner"></div>
        <p>Chargement...</p>
      </div>
    );
  }

  if (!isAuthenticated) {
    return <Navigate to="/" replace />;
  }

  if (requireClient && !isClient) {
    return <Navigate to="/agency" replace />;
  }

  if (requireAgency && !isAgency) {
    return <Navigate to="/client" replace />;
  }

  return children;
};

// Composant pour rediriger les utilisateurs authentifiés
const AuthRedirect = ({ children }) => {
  const { isAuthenticated, isClient, loading } = useAuth();

  if (loading) {
    return (
      <div className="loading-screen">
        <div className="spinner"></div>
        <p>Chargement...</p>
      </div>
    );
  }

  if (isAuthenticated) {
    return <Navigate to={isClient ? '/client' : '/agency'} replace />;
  }

  return children;
};

function App() {
  return (
    <AuthProvider>
      <Router>
        <div className="App">
          <Routes>
            {/* Route de connexion/inscription */}
            <Route
              path="/"
              element={
                <AuthRedirect>
                  <AuthPage />
                </AuthRedirect>
              }
            />

            {/* Routes Client */}
            <Route
              path="/client"
              element={
                <ProtectedRoute requireClient>
                  <ClientDashboard />
                </ProtectedRoute>
              }
            />

            {/* Routes Agence */}
            <Route
              path="/agency"
              element={
                <ProtectedRoute requireAgency>
                  <AgencyDashboard />
                </ProtectedRoute>
              }
            />

            {/* Route par défaut */}
            <Route path="*" element={<Navigate to="/" replace />} />
          </Routes>
        </div>
      </Router>
    </AuthProvider>
  );
}

export default App;
